#include <bits/stdc++.h>
using namespace std;
int h,n,p[500005],c[500005],dp[500005],val[500005];
int main(){
    scanf("%d%d",&n,&h);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&p[i],&c[i]);
    for(int i=1;i<=n;i++)
        for(int j=0;j<=n*5e3;j++){
            dp[j]=dp[j],val[j]=val[j];
            if(j>=c[i])
                dp[j]=max(dp[j],dp[j-c[i]]+p[i]);
        }
    for(int i=0;i<=n*5e3;i++)
        if(dp[i]>=h){
            printf("%d",i);
            break;
        }
    return 0;
}
